```class Solution {
public:
    string crackSafe(int n, int k) {
        string seen = "", ans = "";
        for (int i = 0; i < k * n; i++) {
            string curr = "";
            for (int j = 1; j <= n; j++) {
                curr = (char)('0' + i % k) + curr;
                i /= k;
            }
            for (char c = '0'; c < '0' + k; c++) {
                string t = curr + c;
                if (seen.find(t) == string::npos) {
                    seen += t;
                    ans += c;
                    break;
                }
            }
        }
        for (int i = 0; i < n - 1; i++) ans += '0';
        return ans;
    }
};
